solution:
let angka = [1, 2, 3, 4, 5];
let kuadrat = angka.map(function(n) { return n * n; });
console.log(kuadrat);
let deskripsi = angka.map(function(n, i) { return 'Angka ke-' + (i + 1) + ' adalah ' + n; });
console.log(deskripsi);
